async function httpRequest({ url, method, headers, body }) {
  var options = { method: method || "GET", headers: headers || {} };
  if (body) {
    options.body = typeof body === "string" ? body : JSON.stringify(body);
    if (!options.headers["Content-Type"]) options.headers["Content-Type"] = "application/json";
  }
  var response = await fetch(url, options);
  var contentType = response.headers.get("content-type") || "";
  var data = contentType.includes("application/json") ? await response.json() : await response.text();
  if (!response.ok) throw new Error("HTTP " + response.status + ": " + (typeof data === "string" ? data : JSON.stringify(data)));
  return { status: response.status, headers: Object.fromEntries(response.headers.entries()), data: data };
}

