async function addLabel({ projectId, workItemId, labelName, color }) {
  var labelsResult = await Plane.labels.list(workspaceSlug, projectId);
  var labels = labelsResult.results || labelsResult;
  var existing = labels.find(function(l) { return l.name.toLowerCase() === labelName.toLowerCase(); });
  var label = existing || await Plane.labels.create(workspaceSlug, projectId, { name: labelName, color: color || "#3a3a3a" });
  var item = await Plane.workItems.retrieve(workspaceSlug, projectId, workItemId);
  var currentLabels = item.labels || [];
  if (currentLabels.indexOf(label.id) === -1) {
    await Plane.workItems.update(workspaceSlug, projectId, workItemId, { labels: currentLabels.concat([label.id]) });
  }
  return label;
}

