async function addWorkItem({ projectId, name, description }) {
  let description_html;
  if (description) {
    description_html = description.startsWith("<") ? description : "<p>" + description + "</p>";
  }

  const workItemData = {
    name,
    ...(description ? { description_html } : {})
  }

  return await Plane.workItems.create(workspaceSlug, projectId, workItemData);
}

