async function updateWorkItemState({ projectId, workItemId, state }) {
  const projectStates = await Plane.states.list(workspaceSlug, projectId)
  const targetState = projectStates.results.find((x) => x.name.toLowerCase() == state.toLowerCase())

  if (!targetState) {
    throw new Error('Invalid state')
  }

  return await Plane.workItems.update(workspaceSlug, projectId, workItemId, { state: targetState?.id })
}

